4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
