12	  const aliveKeys = new Set(liveCells.map(cellKey));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const neighbor: Cell = [x + dx, y + dy];
18	      const k = cellKey(neighbor);
19	      const prior = neighborCounts.get(k)?.count ?? 0;
20	      neighborCounts.set(k, { cell: neighbor, count: prior + 1 });
21	    }
22	  }
23	
24	  const nextLiveCells: Cell[] = [];
25	  for (const [k, { cell, count }] of neighborCounts) {
26	    if (count === 3 || (count === 2 && aliveKeys.has(k))) {
27	      nextLiveCells.push(cell);
28	    }
29	  }
